# Security Improvements for app.js

## 1. Add Error Handling Middleware
```javascript
// Add at the end of app.js
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({
    error: 'Internal Server Error',
    message: process.env.NODE_ENV === 'production' ? 'Something went wrong.' : err.message
  });
});
```

## 2. Add Security Headers
```javascript
const helmet = require('helmet');
app.use(helmet());
```

## 3. Add Rate Limiting
```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per window
});

app.use(limiter);
```

## 4. Add Content Security Policy
```javascript
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ['self'],
    scriptSrc: ['self', 'https://trusted-cdn.com'],
    connectSrc: ['self', 'https://api.trusted-domain.com'],
    imgSrc: ['self', 'data:', 'https://trusted-image-domain.com'],
    styleSrc: ['self', 'https://trusted-cdn.com']
  }
}));
```

## 5. Add Request Validation
```javascript
// Add validation middleware for any endpoints that need it
app.get('/users/:id', (req, res, next) => {
  const id = req.params.id;
  if (!isNaN(id)) {
    next();
  } else {
    next(new Error('Invalid user ID'));
  }
}, (req, res) => {
  // handle valid request
});
```

## 6. Add Body Parser Configuration
```javascript
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

## 7. Add X-Content-Type-Options Header
```javascript
app.use(helmet({
  contentSecurityPolicy: false
}));
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  next();
});
```
